local LMapBase = LMapBase
---@class LGuideStoryMap:LMapBase
local LGuideStoryMap = LxClass("LGuideStoryMap", LMapBase)

local Vector3 = Vector3

-----------------------------------------------------------------

-----------------------------------------------------------------
function LGuideStoryMap:LGuideStoryMap()
    self:InitEvents()
end

function LGuideStoryMap:OnDestroy()
    self:DelayFuncClear()

    if self._mainRoleEff then
        self._mainRoleEff:Destroy()
        self._mainRoleEff = nil
    end

    if self._mgr then
        self._mgr:Destroy()
        self._mgr = nil
    end
    LMapBase.OnDestroy(self)
end

function LGuideStoryMap:OnCreate()
    LMapBase.OnCreate(self)
end

function LGuideStoryMap:OnResetMap()
    GF.OpenWnd("UIMinFight")
    GF.OpenWnd("UIGueStory")


    self:SetMapName("MapGuideStory")
end

function LGuideStoryMap:OnEnterMap()
    GF.CloseWndByName("UIPerCreateName")


    self:InitPosData()

    self._mgr = gLGpManager:GetGuideStoryMgrImpl()
    self._mgr:EnterMap(self)
    self._objCtrl = self._mgr:GetObjCtrl()


    self:InitCamera()
    self._onEnterMap = true


    -- 在引导点击进入新手地图时，由于点击完了，执行点击的逻辑，才会执行下一步的引导逻辑，所在在点击时，就进入了地图时，
    -- 导在初始化地图时，引导数据还未完成（实际已完）
    self:DelayFunc(function()
        self:ReadyStartStory()
    end, 0.2)
end

function LGuideStoryMap:OnExitMap()
    self:ReSetCameraSize()

    GF.CloseWndByName("UIGueStory")

    -- local cameraCom = self:GetMapCameraCom()
    -- cameraCom:StartFollowState(nil, Vector3(0, 0, 0), 0)

    local refId = gModelGuideStory:GetCurRefId()
    local step = gModelGuideStory:GetCurStep()
    if refId > 1 and step > 1 and gModelGuideStory:IsStroy(refId) then
        local ref = gModelGuideStory:GetRef(refId)
        local stepRef = gModelGuideStory:GetStepRef(ref.id, step)
        if stepRef and stepRef.stepId then
            gModelGuideStory:SendStoryStep(stepRef.stepId)
        end
    end
    if self._mainRoleEff then
        self._mainRoleEff:Destroy()
        self._mainRoleEff = nil
    end

    self._onEnterMap = nil
    self:DelayFuncClear()
    self._mgr:ExitMap()
end

-- 初始事件
function LGuideStoryMap:InitEvents()
    self:MapEventRecv(EventNames.GUIDE_STORY_STEP_FINISH, function()
        if not self._onEnterMap then
            return
        end
        self:StartGuideNextStep()
    end)
end

-- 初始化位置数据
function LGuideStoryMap:InitPosData()
    -- 地图对象坐标
    self._objPosMap = {}
    local root = self:GetMapTrans()
    local ObjPosTrans = CS.FindTrans(root, "ObjPos")
    for i = 0, ObjPosTrans.childCount - 1 do
        local trans             = ObjPosTrans:GetChild(i)
        local objKey            = trans.name
        local pos               = trans.position
        self._objPosMap[objKey] = pos
    end

    -- 路径坐标
    self._pathMap = {}
    local PathPosTrans = CS.FindTrans(root, "PathList")
    for i = 0, PathPosTrans.childCount - 1 do
        local trans = PathPosTrans:GetChild(i)
        local list  = {}
        for j = 0, trans.childCount - 1 do
            local child  = trans:GetChild(j)
            local objKey = tonumber(child.name)
            local pos    = child.position
            list[objKey] = pos
        end
        self._pathMap[trans.name] = list
    end

    CS.ShowObject(ObjPosTrans, false)
    CS.ShowObject(PathPosTrans, false)
end

-- 获取对象坐标
function LGuideStoryMap:GetObjInitPosByKey(objKey)
    if not self._objPosMap[objKey] then
        printErrorN2("GuideStory", "不存在对象, key:" .. tostring(objKey) .. " 的坐标，请在ui中添加！")
        return Vector3(0, 0, 0)
    end

    return self._objPosMap[objKey]
end

-- 获取路径列表
function LGuideStoryMap:GetPathListByKey(key)
    if not self._pathMap[key] then
        printErrorN2("GuideStory", "路径:" .. tostring(key) .. "，请在ui中添加！")
        return Vector3(0, 0, 0)
    end

    return self._pathMap[key]
end

-- 初始化相机
function LGuideStoryMap:InitCamera()
    local bgImgW = 640
    local bgImgH = 1400
    local mapW = bgImgW * 4 * 0.01
    local mapH = bgImgH * 2 * 0.01

    local UScreen = UnityEngine.Screen
    local screenWidth = UScreen.width * 0.01

    local orthgraphicSize = LUtil.GetCameraSize()
    local cameraCom = self:GetMapCameraCom()
    local min = Vector2(screenWidth * 0.5, orthgraphicSize)
    local max = Vector2(mapW - screenWidth * 0.5, mapH - orthgraphicSize)

    local sceneCamera = gLGameScene:GetCurrentSceneCamera()
    self._OldOrthgraphicSize = sceneCamera.orthographicSize
    sceneCamera.orthographicSize = gModelGuideStory:GetMapCameraSize()
    cameraCom:SetRange(min, max)

    -- 初始位置
    local group = LGuideStoryConst.ObjGroup[1]
    local obj1 = self:GetObjInitPosByKey(group[1].key)
    local obj2 = self:GetObjInitPosByKey(group[2].key)
    local pos = Vector3((obj1.x + obj2.x) * 0.5, (obj1.y + obj2.y) * 0.5, 0)
    local posList = { pos }
    self:CameraMoveByPosList(posList, 0)
end

-- 还原相机设置
function LGuideStoryMap:ReSetCameraSize()
    local sceneCamera = gLGameScene:GetCurrentSceneCamera()
    sceneCamera.orthographicSize = self._OldOrthgraphicSize
end

-- 准备开始剧情
function LGuideStoryMap:ReadyStartStory()
    local refId = gModelGuideStory:GetCurRefId()
    local step = gModelGuideStory:GetCurStep()
    if refId == 0 then
        refId, step = gModelGuideStory:GetUnFinishRefId()
    end

    if refId == 0 or gModelGuideStory:IsGuideStoryFinish() then
        -- 所有引导已完成
        GF.ChangeMap("LFightIdleMap")
        return
    end

    local initMapRefId = refId
    local initMapStep = step

    if gModelGuideStory:IsStroy(refId) then
        if step == 0 then
            -- self:InitMap(refId, 1)
            initMapStep = 1
            step = 2
        else
            local ref = gModelGuideStory:GetRef(refId)
            local groupId = ref.id
            local stepRef = gModelGuideStory:GetStepRef(groupId, step + 1)
            if not stepRef then
                gModelGuideStory:StartGuideStory(ref.next, 0)
                self:ReadyStartStory()
                return
            end

            local index = string.find(stepRef.type or "", "InitMap") or 0
            if index ~= 1 then
                if LOG_INFO_ENABLED then
                    gModelGuideStory:Log("初始化地图失误:" .. refId .. " 步骤:" .. step)
                end
                initMapStep = 1
                step = 2
            else
                initMapStep = step + 1
                step = initMapStep + 1
            end
        end
    else
        local ref = gModelGuideStory:GetRef(refId)
        if gModelGuideStory:IsGuideFinish(refId) then
            gModelGuideStory:StartGuideStory(ref.next, 0)
            self:ReadyStartStory()
            return
        end

        if step == 0 then
            local refId3, step3 = gModelGuideStory:GetUnFinishRefId()
            step = step3
        end

        local refId2 = gModelGuideStory:GetInitMapRefId(refId)
        initMapRefId = refId2
        initMapStep = 1
    end

    self:InitMap(initMapRefId, initMapStep, refId, step)
end

-- 初始化地图
function LGuideStoryMap:InitMap(initMapRefId, initMapStep, refId, step)
    local ref = gModelGuideStory:GetRef(initMapRefId)
    local groupId = ref.id
    local stepRef = gModelGuideStory:GetStepRef(groupId, initMapStep)

    if LOG_INFO_ENABLED then
        gModelGuideStory:Log("初始化地图开始:refId:" ..
            initMapRefId .. " 组:" .. groupId .. " 步骤:" .. initMapStep .. " 即将执行:" .. refId .. " 步骤:" .. step)
    end

    local time = os.clock()
    self[stepRef.type](self, stepRef, function()
        self:InitMapFinish(initMapRefId, initMapStep, refId, step, time)
    end)
end

-- 初始化地图完成
function LGuideStoryMap:InitMapFinish(initMapRefId, initMapStep, refId, step, time)
    local ref = gModelGuideStory:GetRef(initMapRefId)
    local groupId = ref.id
    local leftTime = os.clock() - time
    if LOG_INFO_ENABLED then
        gModelGuideStory:Log("初始化地图结束:refId:" ..
            initMapRefId ..
            " 组:" .. groupId .. " 步骤:" .. initMapStep .. " 即将执行:" .. refId .. " 步骤:" .. step .. " 耗时:" .. leftTime)
    end

    leftTime = math.max(1.5, leftTime + 0.5) -- 可防多次进入地图与等待视觉缓冲

    gModelGuide:EndGuide()
    if gModelGuideStory:IsStroy(refId) then
        self:DelayFunc(function() self:StartGuideStory(refId, step) end, leftTime)
    else
        gModelGuideStory:StartGuideStory(refId, step)

        if LOG_INFO_ENABLED then
            gModelGuideStory:Log("开始引导:" .. step)
        end
        local ref = GameTable.NewPlayerGuideEventRef[step]
        local origin = ref and ref.origin or 0
        if LGuideStoryConst.NeedInCityMap[origin] then
            GF.ChangeMap("LCityMap")
        end
        gModelGuide:StartGuide(step)
    end
end

-- 相机按路径移动
function LGuideStoryMap:CameraMoveByPosList(posList, speed)
    local cameraCom = self:GetMapCameraCom()
    if speed <= 0 then
        cameraCom:SetCameraPos(posList[#posList], 0)
        return 0
    end

    local camera = gLGameScene:GetCurrentSceneCamera()
    local cameraTrans = camera.transform
    local curPos = cameraTrans.position
    curPos.z = 0
    local totalTime = 0
    for i, pos in ipairs(posList) do
        local dis
        if i == 1 then
            dis = Vector3.Distance(curPos, pos)
        else
            dis = Vector3.Distance(posList[i - 1], pos)
        end
        local time = dis / speed
        self:DelayFunc(function() cameraCom:SetCameraPos(pos, time) end, totalTime)
        totalTime = totalTime + time
    end
    return totalTime
end

-- 延迟函数
function LGuideStoryMap:DelayFunc(func, delayTime)
    self._delayFuncList = self._delayFuncList or {}
    local key = LxTimer.DelayTimeCall(func, delayTime)
    table.insert(self._delayFuncList, key)
end

-- 清除延迟函数
function LGuideStoryMap:DelayFuncClear()
    for _, key in ipairs(self._delayFuncList or {}) do
        LxTimer.DelayTimeStop(key)
    end
    self._delayFuncList = {}
end

-- 游戏对象根节点
function LGuideStoryMap:GetObjRootTrans()
    if not self._objRootTrans then
        local root = self:GetMapTrans()
        self._objRootTrans = CS.FindTrans(root, "ObjRoot")
    end
    return self._objRootTrans
end

-- 游戏特效节点
function LGuideStoryMap:GetEffRootTrans()
    if not self._effRootTrans then
        local root = self:GetMapTrans()
        self._effRootTrans = CS.FindTrans(root, "EffRoot")
    end
    return self._effRootTrans
end

