--引导
-----------------------------------------------------------------
-- 开始引导
function LGuideStoryMap:StartGuideStory(refId, step)
    gModelGuideStory:StartGuideStory(refId, step)

    local ref = gModelGuideStory:GetRef(refId)
    local groupId = ref.id
    local stepRef = gModelGuideStory:GetStepRef(groupId, step)
    if not self[stepRef.type] then
        if LOG_INFO_ENABLED then
            gModelGuideStory:Log("不存在引导类型,id:" .. tostring(refId) .. " 步骤:" .. tostring(step), stepRef)
        end
        return
    end

    if LOG_INFO_ENABLED then
        if tostring(stepRef.type) == "Dialogue" then
            gModelGuideStory:Log("开始执行函数:" .. tostring(stepRef.type) .. ":" .. tostring(stepRef.dialogueId))
        else
            gModelGuideStory:Log("开始执行函数:" .. tostring(stepRef.type))
        end
    end

    if step > 1 then
        local lastStepRef = gModelGuideStory:GetStepRef(groupId, step - 1)
        if lastStepRef.stepId then
            gModelGuideStory:SendStoryStep(lastStepRef.stepId)
        end
    end

    local delayTime = self[stepRef.type](self, stepRef) or 0

    if stepRef.save then
        gModelGuideStory:PreSaveCurGuide()
    elseif stepRef.saveCur then
        gModelGuideStory:SaveCurGuide()
    end

    if delayTime == -1 then
        return
    end
    delayTime = delayTime + (stepRef.delay or 0)
    if delayTime > 0 then
        self:DelayFunc(function() self:StartGuideNextStep() end, delayTime)
        return
    end
    self:StartGuideNextStep()
end

-- 开始引导下一步
function LGuideStoryMap:StartGuideNextStep()
    local refId = gModelGuideStory:GetCurRefId()

    if not gModelGuideStory:IsStroy(refId) then
        return
    end

    local step        = gModelGuideStory:GetCurStep()
    local ref         = gModelGuideStory:GetRef(refId)
    local groupId     = ref.id
    local nextStepRef = gModelGuideStory:GetStepRef(groupId, step + 1)

    if nextStepRef then
        self:StartGuideStory(refId, step + 1)
        return
    end

    if ref.next == 0 then
        -- 引导已完成
        GF.ChangeMap("LFightIdleMap")
        return
    end

    local nextRef = gModelGuideStory:GetRef(ref.next)
    if gModelGuideStory:IsStroy(nextRef.refId) then
        self:StartGuideStory(nextRef.refId, 1)
        return
    end

    step = gModelGuideStory:GetFirstGuideId(nextRef.refId)
    gModelGuideStory:StartGuideStory(nextRef.refId, step)
    gModelGuide:StartGuide(step)
end

-- 相机移动
function LGuideStoryMap:CameraMove(stepRef)
    local time = 0
    local posList = stepRef.posList
    local speed = gModelGuideStory:GetDefaultCameraSpeed()
    if stepRef.speedType == 1 then
        speed = gModelGuideStory:GetBlockCameraSpeed()
    end

    local list = {}
    if posList == "ToMainRole" then
        local obj = self._objCtrl:GetMainRoleObj()
        local pos = obj:GetPosition()
        table.insert(list, pos)
    elseif posList == "ToGroup" then
        local groups = LGuideStoryConst.ObjGroup
        for _, index in ipairs(stepRef.groupList) do
            local group = groups[index]
            local obj1 = self:GetObjInitPosByKey(group[1].key)
            local obj2 = self:GetObjInitPosByKey(group[2].key)
            local pos = Vector3((obj1.x + obj2.x) * 0.5, (obj1.y + obj2.y) * 0.5, 0)
            table.insert(list, pos)
        end
    elseif posList == "ToKey" then
        local obj = self._objCtrl:GetObjByKey(stepRef.objKey)
        local pos = obj:GetPosition()
        table.insert(list, pos)
    end

    if stepRef.endOffset then
        local endPos = list[#list]
        endPos.x = endPos.x + stepRef.endOffset.x
        endPos.y = endPos.y + stepRef.endOffset.y
    end
    time = time + self:CameraMoveByPosList(list, speed)

    return time
end

-- 黑幕故事
function LGuideStoryMap:Block(stepRef)
    local param = {}
    param.dialogueId = stepRef.dialogueId
    FireEvent(EventNames.GUIDE_STORY_BLACK, param)
    return -1
end

-- 对白
function LGuideStoryMap:Dialogue(stepRef)
    local obj = self._objCtrl:GetObjByKey(stepRef.objKey)
    if not obj then
        printErrorN2("GuideStory", "地图不存在对象, key:" .. tostring(stepRef.objKey))
        return -1
    end

    local worldPos = obj:GetPosition()
    worldPos.y = worldPos.y

    local param = {}
    param.dialogueId = stepRef.dialogueId
    param.worldPos = worldPos

    FireEvent(EventNames.GUIDE_STORY_DIALOGUE, param)
    return -1
end

-- 地图对象消失
function LGuideStoryMap:DisappearsObj(stepRef)
    self._objCtrl:DeleteObjByKey(stepRef.objKey)
    return 0
end

-- 主角移动
function LGuideStoryMap:MainRoleMove(stepRef)
    local obj = self._objCtrl:GetMainRoleObj()
    if not obj then
        printErrorN2("GuideStory", "地图不存在主角")
        return -1
    end

    local time = self._objCtrl:MainRoleMove(stepRef)
    local cameraCom = self:GetMapCameraCom()
    cameraCom:StartFollowState(obj:GetDisplayTrans(), Vector3(0, 0, 0), 0)
    return time
end

-- 创建主角
function LGuideStoryMap:CreateMainRole(stepRef)
    local param = {
        pos = self:GetObjInitPosByKey(stepRef.posKey),
        noFollow = stepRef.noFollow,
    }
    if stepRef.showAni then
        self._objCtrl:CreateMainRole(param, function() self:ShowEnterAnim() end)
    else
        self._objCtrl:CreateMainRole(param, function() self:StartGuideNextStep() end)
    end
    return -1
end

-- 显示出场动画
function LGuideStoryMap:ShowEnterAnim()
    if self._mainRoleEff then
        self._mainRoleEff:Destroy()
        self._mainRoleEff = nil
    end

    local mainObj = self._objCtrl:GetMainRoleObj()
    local mainRoleTrans = mainObj:GetDisplayTrans()

    local dp = LDisplayEffect:New()
    dp:CreateEffect(self:GetObjRootTrans(), "fx_xsjq_chuchang")
    dp:SetResTag(CS.RES_TAG_SCENE)
    self._mainRoleEff = dp
    dp:SetLoadedFunction(function()
        if not self._mainRoleEff then
            return
        end

        local curPos = mainRoleTrans.position
        local trans = self._mainRoleEff:GetDisplayTrans()
        curPos.x = curPos.x
        trans.position = curPos

        self._objCtrl:PlayEnterAnim(function() self:StartGuideNextStep() end)
    end)

    self._objCtrl:ShowMainRoleAndFollow(false)
    dp:StartLoadEffect()
end

-- 对象加入跟随着
function LGuideStoryMap:AddFollow(stepRef)
    local heroRefId = nil
    if stepRef.addCur then
        local ref = gModelGuideStory:GetObjRef(stepRef.objKey)
        local heroEffectRef = GameTable.CharacterEffectRef[ref.heroEff]
        heroRefId = heroEffectRef and heroEffectRef.heroType
    end

    self._objCtrl:AddFollow(stepRef.objKey, function()
        gModelHero:PopGetHero(function()
            self:StartGuideNextStep()
            gModelBattle:DoOneKeyMainFormation()
        end, heroRefId)
    end)
    return -1
end

-- 创新新角色
function LGuideStoryMap:NewObj(stepRef)
    self._objCtrl:NewObj(stepRef, function() self:StartGuideNextStep() end)

    return -1
end

-- 执行引导
function LGuideStoryMap:Guide(guideStep)
    gModelGuide:StartGuide(guideStep.guideId)
    return -1
end

