    -- local combatData = {
    --     combatType = LCombatTypeConst.COMBAT_MAIN,
    --     -- meName = gModelPlayer:GetPlayerName()
    -- }
    -- gModelBattle:StartAfterSetFormation(combatData)

    gModelBattle:DoOneKeyMainBattle()

