-- 初始化地图1
function LGuideStoryMap:InitMap1(stepRef, callback)
    self:InitMapObj(nil, nil, function()
        if callback then
            callback()
        else
            self:StartGuideNextStep()
        end
    end)

    -- local pos = self:GetObjInitPosByKey("Role1")


    local group = LGuideStoryConst.ObjGroup[1]
    local obj1 = self:GetObjInitPosByKey(group[1].key)
    local obj2 = self:GetObjInitPosByKey(group[2].key)
    local pos = Vector3((obj1.x + obj2.x) * 0.5, (obj1.y + obj2.y) * 0.5, 0)


    -- local pos = self:GetObjInitPosByKey("Role1")

    local posList = { pos }
    self:CameraMoveByPosList(posList, 0)
    return -1
end

-- 初始化地图2
function LGuideStoryMap:InitMap1_2(stepRef, callback)
    local pos = stepRef.pos
    if stepRef.posType == "EndPath" then
        local posList = self:GetPathListByKey(pos)
        pos = posList[#posList]
    elseif stepRef.posType == "ToKey" then
        pos = self:GetObjInitPosByKey(stepRef.objKey)
    end

    local posList = { pos }
    self:CameraMoveByPosList(posList, 0)

    local times = 2
    local function finish()
        times = times - 1
        if times <= 0 then
            if callback then
                callback()
            else
                self:StartGuideNextStep()
            end
        end
    end

    local param = {
        pathKey = stepRef.pos,
        pos = pos,
        flipx = stepRef.flipx,
    }

    self._objCtrl:CreateMainRole(param, finish, stepRef.ignoreEnd)

    self:InitMapObj(stepRef.disappears, stepRef.idles, finish)
    return -1
end

-- 初始化地图2
function LGuideStoryMap:InitMap2(stepRef, callback)
    local mainObj = self._objCtrl:GetMainRoleObj()
    if mainObj then
        -- 地图已初始化完

        if stepRef.saveFormation then
            gModelBattle:DoOneKeyMainFormation()
        end

        if callback then
            callback()
        else
            self:StartGuideNextStep()
        end

        return -1
    end

    -- 重新登陆进入
    return self:InitMap1_2(stepRef, callback)
end

-- 初始化地图3
function LGuideStoryMap:InitMap3(stepRef, callback)
    local mainObj = self._objCtrl:GetMainRoleObj()
    if mainObj then
        -- 地图已初始化完

        if callback then
            callback()
        else
            self:StartGuideNextStep()
        end

        return -1
    end
    -- self:CreateLoopDialogueObj(stepRef) -- 去掉：2020-12-6

    return self:InitMap1_2(stepRef, callback)
end

-- 创建循环对白
function LGuideStoryMap:CreateLoopDialogueObj(stepRef, callback)
    local monsterList = {}
    local parent      = self:GetObjRootTrans()
    for k, v in ipairs(stepRef.dialogueList) do
        local pos = self:GetObjInitPosByKey(v.key .. v.keySuffix)

        local ref = gModelGuideStory:GetObjRef(v.key)
        table.insert(monsterList, {
            key     = v.key,
            flipx   = v.flipx,
            heroEff = ref.heroEff,
            scale   = ref.scale,
            parent  = parent,
            pos     = pos,

        })
    end
    self._objCtrl:CreateObjList(monsterList, callback)
end

-- 初始化Boss
function LGuideStoryMap:InitMapBoss(stepRef, callback)
    local pos = stepRef.pos
    if stepRef.posType == "EndPath" then
        local posList = self:GetPathListByKey(pos)
        pos = posList[#posList]
    end
    local posList = { pos }
    self:CameraMoveByPosList(posList, 0)

    local monsterFlipx = stepRef.monsterFlipx
    local monsterList  = {}
    local parent       = self:GetObjRootTrans()
    for _, v in ipairs(stepRef.monsterList) do
        local pos = self:GetObjInitPosByKey(v.key)
        local ref = gModelGuideStory:GetObjRef(v.key)
        local heroEff = v.heroEff or ref.heroEff
        table.insert(monsterList, {
            key     = v.key,
            flipx   = ref.flipx == 0,
            heroEff = heroEff,
            parent  = parent,
            pos     = pos,
            scale   = ref.scale,
        })
    end
    local times = 2
    local function finish()
        times = times - 1
        if times <= 0 then
            if callback then
                callback()
            else
                self:StartGuideNextStep()
            end
        end
    end

    local param = {
        flipx   = not monsterFlipx,
        pos     = pos,
        pathKey = stepRef.pos,
    }
    self._objCtrl:CreateMainRole(param, finish)
    self._objCtrl:CreateObjList(monsterList, finish)

    return -1
end

-- 循环对白
function LGuideStoryMap:LoopDialogue(stepRef)
    local dataList = {}
    for k, data in ipairs(stepRef.dialogueList) do
        local obj = self._objCtrl:GetObjByKey(data.key)
        if obj then
            local worldPos = obj:GetPosition()
            worldPos.y = worldPos.y

            table.insert(dataList, {
                id       = data.id,
                worldPos = worldPos,
                delay    = data.delay,
            })
        end
    end
    FireEvent(EventNames.GUIDE_STORY_DIALOGUE_LOOP, { delay = stepRef.delay, dataList = dataList })

    return 0
end

-- 初始化地图对象
function LGuideStoryMap:InitMapObj(disappears, idles, callback)
    local dataList = {}

    local disappearMap = {}
    for _, v in ipairs(disappears or {}) do
        disappearMap[v] = true
    end

    local idleMap = {}
    for _, v in ipairs(idles or {}) do
        idleMap[v] = true
    end

    local effTrans = self:GetEffRootTrans()
    local objTrans = self:GetObjRootTrans()
    for k, v in ipairs(LGuideStoryConst.ObjGroup) do
        for kk, data in ipairs(v) do
            if not disappearMap[data.key] then
                local ref = gModelGuideStory:GetObjRef(data.key)
                local atkData = {}

                local status = ref.spine == "attack1" and LGuideStoryConst.ObjStatus.Atk or LGuideStoryConst.ObjStatus.Idle
                if idleMap[data.key] then
                    status = LGuideStoryConst.ObjStatus.Idle
                end

                local pos = self:GetObjInitPosByKey(data.key)
                if #v == 2 then
                    -- 只有当为2个人时，才存在两两互打的情况
                    local effPos
                    if kk == 1 then
                        effPos = self:GetObjInitPosByKey(v[2].key)
                    else
                        effPos = self:GetObjInitPosByKey(v[1].key)
                    end

                    atkData = {
                        effRes   = ref.atkEff,
                        effTrans = effTrans,
                        effPos   = effPos,
                        effTime  = ref.effTime
                    }
                end
                local param = {
                    flipx   = ref.flipx == 0,
                    atkData = atkData,
                    heroEff = ref.heroEff,
                    parent  = objTrans,
                    status  = status,
                    pos     = pos,
                    key     = data.key,
                    scale   = ref.scale
                }

                table.insert(dataList, param)
            end
        end
    end

    if #dataList == 0 then
        if callback then
            callback()
        end
        return
    end

    self._objCtrl:CreateObjList(dataList, callback)
end

return LGuideStoryMap
